// db.js
require('dotenv').config();
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT,
});

pool.on('error', (err) => {
  console.error('Unexpected error on idle client', err);
  process.exit(-1);
});

module.exports = {
  query: (text, params) => pool.query(text, params),
  getClient: () => pool.connect(),
};

// services/user-service.js
const db = require('../db');

const userService = {
  async getAllUsers() {
    const { rows } = await db.query('SELECT id, name, email, created_at FROM users ORDER BY created_at DESC');
    return rows;
  },

  async getUserById(id) {
    const { rows } = await db.query('SELECT id, name, email, created_at FROM users WHERE id = $1', [id]);
    return rows[0];
  },

  async createUser(name, email) {
    const { rows } = await db.query(
      'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id, name, email, created_at',
      [name, email]
    );
    return rows[0];
  },

  async updateUser(id, name, email) {
    const { rows } = await db.query(
      'UPDATE users SET name = $1, email = $2 WHERE id = $3 RETURNING id, name, email, created_at',
      [name, email, id]
    );
    return rows[0];
  },

  async deleteUser(id) {
    const { rowCount } = await db.query('DELETE FROM users WHERE id = $1', [id]);
    return rowCount > 0;
  },
};

module.exports = userService;

// services/product-service.js
const db = require('../db');

const productService = {
  async getAllProducts() {
    const { rows } = await db.query('SELECT id, name, description, price, stock, created_at FROM products ORDER BY created_at DESC');
    return rows;
  },

  async getProductById(id) {
    const { rows } = await db.query('SELECT id, name, description, price, stock, created_at FROM products WHERE id = $1', [id]);
    return rows[0];
  },

  async createProduct(name, description, price, stock) {
    const { rows } = await db.query(
      'INSERT INTO products (name, description, price, stock) VALUES ($1, $2, $3, $4) RETURNING id, name, description, price, stock, created_at',
      [name, description, price, stock]
    );
    return rows[0];
  },

  async updateProduct(id, name, description, price, stock) {
    const { rows } = await db.query(
      'UPDATE products SET name = $1, description = $2, price = $3, stock = $4 WHERE id = $5 RETURNING id, name, description, price, stock, created_at',
      [name, description, price, stock, id]
    );
    return rows[0];
  },

  async deleteProduct(id) {
    const { rowCount } = await db.query('DELETE FROM products WHERE id = $1', [id]);
    return rowCount > 0;
  },
};

module.exports = productService;

// routes/users.js
const express = require('express');
const router = express.Router();
const userService = require('../services/user-service');

// Get all users
router.get('/', async (req, res) => {
  try {
    const users = await userService.getAllUsers();
    res.json(users);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Get a single user by ID
router.get('/:id', async (req, res) => {
  try {
    const user = await userService.getUserById(req.params.id);
    if (!user) {
      return res.status(404).json({ msg: 'User not found' });
    }
    res.json(user);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Create a new user
router.post('/', async (req, res) => {
  const { name, email } = req.body;
  if (!name || !email) {
    return res.status(400).json({ msg: 'Please include name and email' });
  }
  try {
    const newUser = await userService.createUser(name, email);
    res.status(201).json(newUser);
  } catch (err) {
    console.error(err.message);
    if (err.code === '23505') { // PostgreSQL unique violation error code
      return res.status(400).json({ msg: 'Email already exists' });
    }
    res.status(500).send('Server Error');
  }
});

// Update a user
router.put('/:id', async (req, res) => {
  const { name, email } = req.body;
  if (!name || !email) {
    return res.status(400).json({ msg: 'Please include name and email' });
  }
  try {
    const updatedUser = await userService.updateUser(req.params.id, name, email);
    if (!updatedUser) {
      return res.status(404).json({ msg: 'User not found' });
    }
    res.json(updatedUser);
  } catch (err) {
    console.error(err.message);
    if (err.code === '23505') {
      return res.status(400).json({ msg: 'Email already exists' });
    }
    res.status(500).send('Server Error');
  }
});

// Delete a user
router.delete('/:id', async (req, res) => {
  try {
    const deleted = await userService.deleteUser(req.params.id);
    if (!deleted) {
      return res.status(404).json({ msg: 'User not found' });
    }
    res.json({ msg: 'User deleted successfully' });
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

module.exports = router;

